  // Se for depois das 20h LOCAL, agenda para 9h LOCAL do próximo dia
  proximoHorario.setUTCDate(proximoHorario.getUTCDate() + 1);
  proximoHorario.setUTCHours(config.horario_comercial.inicio - config.timezone_offset, 0, 0, 0);
}

