  agente_id: body.agente_id,
  config_whatsapp_number: body.config_whatsapp_number,
  "dinastia-token": body["dinastia-token"],
  lead_data: body.lead_data,
  tentativa: proximaTentativa
};

// ========================================
// GERA ID ÚNICO PARA O SCHEDULER
// ========================================
const leadId = $('Webhook').first().json.body['lead-id'];
const schedulerId = `${leadId}_fup${proximaTentativa}`;

// ========================================
// RETORNA TUDO QUE VOCÊ PRECISA
