    agendar_proximo: true,

    // Dados para o Scheduler
    proxima_tentativa: proximaTentativa,
    horario_agendado: horarioAgendadoISO,  // ISO padrão (UTC)
    horario_agendado_local: horarioAgendadoLocal,  // Se scheduler preferir
