      if (item?.output !== undefined) {
        const found = extractLLMOutput(item.output);
        if (found) return found;
      }
      // Fallback: varrer o item inteiro
      const found = extractLLMOutput(item);
      if (found) return found;
    }
  }

  // 2️⃣ Se já for objeto com campos esperados
  if (typeof input === 'object') {
    if (input.should_send !== undefined) return input;
    // Caso esteja dentro de output/data/result/etc
    for (const key of ['output', 'data', 'result', 'response']) {
      if (input[key] !== undefined) {
        const found = extractLLMOutput(input[key]);
        if (found) return found;
      }
    }
    // Varredura genérica
    for (const value of Object.values(input)) {
      const found = extractLLMOutput(value);
      if (found) return found;
    }
  }

  // 3️⃣ Se for string
  if (typeof input === 'string') {
    // Tentar JSON direto
    try {
      const parsed = JSON.parse(input);
      return extractLLMOutput(parsed);
    } catch (_) {}

    // Extrair JSON de dentro do texto
    const jsonMatch = input.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        const parsed = JSON.parse(jsonMatch[0]);
        return extractLLMOutput(parsed);
      } catch (_) {}
    }

    // Último fallback: regex
    const shouldSend = input.match(/"should_send"\s*:\s*(true|false)/);
    if (shouldSend) {
      return {
        should_send: shouldSend[1] === 'true',
        message: input.match(/"message"\s*:\s*"([^"]+)"/)?.[1] ?? null,
        reasoning: input.match(/"reasoning"\s*:\s*"([^"]+)"/)?.[1] ?? null,
        stop_chain: input.match(/"stop_chain"\s*:\s*(true|false)/)?.[1] === 'true'
      };
    }
  }

  return null;
}

// 🔹 Função auxiliar para sanitizar strings JSON
function sanitizeJsonString(str) {
  if (typeof str !== 'string') return str;

  return str
    .replace(/\\/g, '\\\\')    // Escapa barras invertidas primeiro
    .replace(/"/g, '\\"')       // Escapa aspas duplas
    .replace(/\n/g, '\\n\\n')   // Converte \n em \\n\\n (duplo)
    .replace(/\r/g, '\\r')      // Escapa retornos de carro
    .replace(/\t/g, '\\t');     // Escapa tabs
}

// 🔹 USO REAL (exatamente para seu caso)
const normalized = extractLLMOutput($json);

// 🔹 OUTPUT FINAL NO FORMATO CORRETO COM SANITIZAÇÃO
return {
  output: {
    should_send: normalized?.should_send ?? false,
    message: normalized?.message ? sanitizeJsonString(normalized.message) : null,
    reasoning: normalized?.reasoning ? sanitizeJsonString(normalized.reasoning) : 'Fallback acionado: saída mal formatada',
    stop_chain: normalized?.stop_chain ?? false
  }
};
